# Quiz Game
print("=== Python Quiz ===")
score = 0

answer1 = input("Q1: What symbol starts a comment in Python? ")
if answer1 == "#":
    print("Correct!")
    score += 1
else:
    print("Wrong! It's #")

answer2 = input("Q2: What function prints to the screen? ")
if answer2 == "print":
    print("Correct!")
    score += 1
else:
    print("Wrong! It's print")

answer3 = input("Q3: What do you use to get user input? ")
if answer3 == "input":
    print("Correct!")
    score += 1
else:
    print("Wrong! It's input")

print(f"\nYou got {score}/3!")
if score == 3:
    print("Perfect score!")
elif score == 2:
    print("Great job!")
else:
    print("Keep practicing!")
